import Image from 'next/image'
import Link from 'next/link'
import { products, formatPrice, type Product } from '@/lib/products'

// ═══════════════════════════════════════════════════════════════════════════
// COLLECTION PAGE - "Le Showroom"
// Layout asymétrique avec filtres par texture
// ═══════════════════════════════════════════════════════════════════════════

export const metadata = {
    title: 'Collection',
    description: 'Découvrez notre collection d\'étuis à lunettes artisanaux en Wax, Cuir et Raphia.',
}

// Composant carte produit avec style variable selon sa position
function ProductCard({ product, size }: { product: Product; size: 'large' | 'small' }) {
    return (
        <Link
            href={`/product/${product.slug}`}
            className={`group relative block overflow-hidden rounded-2xl bg-white shadow-glass transition-all duration-500 hover:shadow-glass-xl ${size === 'large' ? 'aspect-[3/4]' : 'aspect-square'
                }`}
        >
            {/* Image produit */}
            <Image
                src={product.images[0]}
                alt={product.title}
                fill
                className="object-cover transition-transform duration-700 group-hover:scale-105"
            />

            {/* Overlay gradient */}
            <div className="absolute inset-0 bg-gradient-to-t from-petrol/70 via-petrol/0 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />

            {/* Badge Nouveau */}
            {product.new && (
                <span className="absolute top-4 left-4 px-3 py-1 bg-gold text-white text-xs font-mono uppercase rounded-full z-10">
                    Nouveau
                </span>
            )}

            {/* Badge Matière */}
            <span className="absolute top-4 right-4 px-3 py-1 bg-white/80 backdrop-blur-sm text-petrol text-xs font-mono uppercase rounded-full z-10">
                {product.materialLabel}
            </span>

            {/* Info produit au hover */}
            <div className="absolute bottom-0 left-0 right-0 p-6 text-white translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-300">
                <h3 className="font-display text-xl md:text-2xl mb-1">{product.title}</h3>
                <p className="text-sm text-white/80 mb-2">{product.subtitle}</p>
                <p className="font-mono text-gold text-lg">{formatPrice(product.price)}</p>
            </div>
        </Link>
    )
}

export default function CollectionPage() {
    // Créer un layout asymétrique : 1 grand, 2 petits en alternance
    const renderAsymmetricGrid = () => {
        const elements: React.ReactNode[] = []
        let i = 0

        while (i < products.length) {
            // Pattern : 1 grand à gauche + 2 petits à droite (ou inversé)
            const isEvenGroup = Math.floor(i / 3) % 2 === 0

            if (i + 2 < products.length) {
                // Groupe de 3 produits avec layout asymétrique
                elements.push(
                    <div key={`group-${i}`} className={`grid md:grid-cols-2 gap-6 ${isEvenGroup ? '' : 'md:grid-flow-col-dense'}`}>
                        {/* Grand produit */}
                        <div className={`${isEvenGroup ? 'md:row-span-2' : 'md:row-span-2 md:col-start-2'}`}>
                            <ProductCard product={products[i]} size="large" />
                        </div>
                        {/* Petits produits */}
                        <div className={isEvenGroup ? '' : 'md:col-start-1'}>
                            <ProductCard product={products[i + 1]} size="small" />
                        </div>
                        <div className={isEvenGroup ? '' : 'md:col-start-1'}>
                            <ProductCard product={products[i + 2]} size="small" />
                        </div>
                    </div>
                )
                i += 3
            } else {
                // Produits restants en grille simple
                elements.push(
                    <div key={`remaining-${i}`} className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {products.slice(i).map((product) => (
                            <ProductCard key={product.id} product={product} size="small" />
                        ))}
                    </div>
                )
                break
            }
        }

        return elements
    }

    return (
        <div className="min-h-screen">
            {/* ═══════════════════════════════════════════════════════════════════
          NAVIGATION
          ═══════════════════════════════════════════════════════════════════ */}
            <nav className="fixed top-0 left-0 right-0 z-50 px-6 py-4 md:px-12 bg-sand/80 backdrop-blur-md">
                <div className="flex items-center justify-between">
                    <Link
                        href="/"
                        className="font-display text-2xl md:text-3xl text-petrol hover:text-terracotta transition-colors"
                    >
                        Glory<span className="text-gold">.</span>
                    </Link>

                    <div className="hidden md:flex items-center gap-8 font-mono text-sm uppercase tracking-wider">
                        <Link href="/atelier" className="hover:text-terracotta transition-colors">
                            L&apos;Atelier
                        </Link>
                        <Link href="/collection" className="text-terracotta">
                            Collection
                        </Link>
                        <Link href="/pro" className="hover:text-terracotta transition-colors">
                            Espace Pro
                        </Link>
                        <Link
                            href="https://wa.me/22500000000"
                            target="_blank"
                            className="btn-gold text-xs py-2 px-4"
                        >
                            Commander
                        </Link>
                    </div>

                    <button className="md:hidden flex flex-col gap-1.5 p-2" aria-label="Menu">
                        <span className="w-6 h-0.5 bg-petrol"></span>
                        <span className="w-4 h-0.5 bg-petrol"></span>
                    </button>
                </div>
            </nav>

            {/* ═══════════════════════════════════════════════════════════════════
          HEADER
          ═══════════════════════════════════════════════════════════════════ */}
            <section className="pt-32 pb-16 px-6">
                <div className="max-w-6xl mx-auto text-center">
                    <p className="font-mono text-sm uppercase tracking-[0.3em] text-terracotta mb-4">
                        Le Showroom
                    </p>
                    <h1 className="font-display text-5xl md:text-7xl mb-6">
                        Notre Collection
                    </h1>
                    <p className="text-lg text-petrol/70 max-w-2xl mx-auto">
                        Chaque étui est une pièce unique, confectionnée à la main dans notre atelier d&apos;Abidjan.
                        Sélectionnez votre matière préférée et trouvez l&apos;étui qui vous ressemble.
                    </p>
                </div>
            </section>

            {/* ═══════════════════════════════════════════════════════════════════
          FILTRES PAR MATIÈRE
          ═══════════════════════════════════════════════════════════════════ */}
            <section className="pb-12 px-6">
                <div className="max-w-6xl mx-auto">
                    <div className="flex flex-wrap items-center justify-center gap-4">
                        <span className="font-mono text-sm uppercase tracking-wider text-petrol/50 mr-4">
                            Filtrer par :
                        </span>

                        {/* Bouton Tous */}
                        <button className="px-6 py-3 bg-petrol text-white font-mono text-sm uppercase tracking-wider rounded-full transition-all hover:bg-petrol-600">
                            Tous
                        </button>

                        {/* Boutons matières avec pastilles visuelles */}
                        <button className="group flex items-center gap-2 px-6 py-3 border-2 border-petrol/20 hover:border-terracotta font-mono text-sm uppercase tracking-wider rounded-full transition-all">
                            <span className="w-4 h-4 rounded-full bg-gradient-to-br from-terracotta to-gold"></span>
                            Wax
                        </button>

                        <button className="group flex items-center gap-2 px-6 py-3 border-2 border-petrol/20 hover:border-terracotta font-mono text-sm uppercase tracking-wider rounded-full transition-all">
                            <span className="w-4 h-4 rounded-full bg-gradient-to-br from-amber-800 to-amber-600"></span>
                            Cuir
                        </button>

                        <button className="group flex items-center gap-2 px-6 py-3 border-2 border-petrol/20 hover:border-terracotta font-mono text-sm uppercase tracking-wider rounded-full transition-all">
                            <span className="w-4 h-4 rounded-full bg-gradient-to-br from-amber-200 to-amber-100"></span>
                            Raphia
                        </button>

                        <button className="group flex items-center gap-2 px-6 py-3 border-2 border-petrol/20 hover:border-terracotta font-mono text-sm uppercase tracking-wider rounded-full transition-all">
                            <span className="w-4 h-4 rounded-full bg-gradient-to-br from-petrol to-petrol-400"></span>
                            Textile
                        </button>
                    </div>
                </div>
            </section>

            {/* ═══════════════════════════════════════════════════════════════════
          GRILLE PRODUITS ASYMÉTRIQUE
          ═══════════════════════════════════════════════════════════════════ */}
            <section className="pb-32 px-6">
                <div className="max-w-6xl mx-auto space-y-8">
                    {renderAsymmetricGrid()}
                </div>
            </section>

            {/* ═══════════════════════════════════════════════════════════════════
          CTA COMMANDER
          ═══════════════════════════════════════════════════════════════════ */}
            <section className="py-20 px-6 bg-petrol text-white text-center">
                <h2 className="font-display text-3xl md:text-4xl mb-4">
                    Un modèle vous plaît ?
                </h2>
                <p className="text-white/70 mb-8 max-w-md mx-auto">
                    Commandez directement via WhatsApp. Nous vous accompagnons de la sélection à la livraison.
                </p>
                <Link
                    href="https://wa.me/22500000000?text=Bonjour, je souhaite commander un étui Glory Cases."
                    target="_blank"
                    className="btn-gold"
                >
                    Commander via WhatsApp
                </Link>
            </section>

            {/* Footer */}
            <footer className="py-12 px-6 border-t border-petrol/10 text-center">
                <Link href="/" className="font-display text-2xl text-petrol">
                    Glory<span className="text-gold">.</span>
                </Link>
                <p className="mt-4 text-sm text-petrol/50">
                    © 2024 Glory Cases. Fait avec ♥ à Abidjan
                </p>
            </footer>
        </div>
    )
}
